WHERE downloads > (SELECT AVG(downloads) FROM packages);

SELECT * 
FROM analyses 
WHERE analysis_id = 'specific_analysis_id';

SELECT AVG(downloads) AS avg_downloads
FROM packages
WHERE downloads > 500;
